#include <cstdlib>
#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> h(4);
    for (int i = 0; i < 4; ++i) {
        cin >> h[i];
    }

    int answer = h[1];
    int bestDiff = abs(h[1] - h[0]);

    for (int i = 2; i < 4; ++i) {
        int diff = abs(h[i] - h[0]);
        // 中文注释：优先选择身高差更小的人；差值相同则选择较矮的人。
        if (diff < bestDiff || (diff == bestDiff && h[i] < answer)) {
            bestDiff = diff;
            answer = h[i];
        }
    }

    cout << answer << '\n';
    return 0;
}

