bool isBinaryPalindrome(int x) {
    string bits;
    while (x > 0) {
        bits.push_back(char('0' + x % 2));
        x /= 2;
    }
    reverse(bits.begin(), bits.end());

    int left = 0;
    int right = static_cast<int>(bits.size()) - 1;
    while (left < right) {
        if (bits[left] != bits[right]) {
            return false;
        }
        ++left;
        --right;
    }
    return true;
}

