using namespace std;

struct GiftBox {
    int id;
    long long sum;
    int maxPrice;
    int minPrice;
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
    cin >> n >> k;
    vector<GiftBox> boxes;

    for (int i = 1; i <= n; ++i) {
        long long sum = 0;
        int maxPrice = 0;
        int minPrice = 1000000000;
        for (int j = 0; j < k; ++j) {
            int price;
            cin >> price;
            sum += price;
            maxPrice = max(maxPrice, price);
            minPrice = min(minPrice, price);
        }
        boxes.push_back({i, sum, maxPrice, minPrice});
    }

    sort(boxes.begin(), boxes.end(), [](const GiftBox& a, const GiftBox& b) {
        // 中文注释：四个排序关键字按题目顺序依次比较。
        if (a.sum != b.sum) return a.sum < b.sum;
        if (a.maxPrice != b.maxPrice) return a.maxPrice < b.maxPrice;
        if (a.minPrice != b.minPrice) return a.minPrice < b.minPrice;
        return a.id < b.id;
    });

    for (int i = 0; i < n; ++i) {
        if (i > 0) {
            cout << ' ';
        }
        cout << boxes[i].id;
    }
    cout << '\n';
    return 0;
}

